<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml" Title="VCF 9.1 ESX Host Validation and JSON Generator" Height="850" Width="1400" MinWidth="1040" WindowStartupLocation="CenterScreen" Background="#050A0D" Foreground="#E6E6E6" FontFamily="Segoe UI"><Window.Resources><Style TargetType="Button"><Setter Property="Background" Value="#D7DCE2"/><Setter Property="Foreground" Value="#111111"/><Setter Property="BorderBrush" Value="#7F8A96"/><Setter Property="Padding" Value="8,4"/><Setter Property="Margin" Value="4,3,4,3"/><Setter Property="Height" Value="28"/></Style><Style TargetType="TextBlock"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Margin" Value="0,4,8,4"/></Style><Style TargetType="TextBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Padding" Value="4"/><Setter Property="CaretBrush" Value="#E6E6E6"/></Style><Style TargetType="PasswordBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Padding" Value="4"/><Setter Property="CaretBrush" Value="#E6E6E6"/></Style><Style TargetType="ComboBox"><Setter Property="Height" Value="24"/></Style><Style TargetType="GroupBox"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Background" Value="#0A1418"/><Setter Property="BorderBrush" Value="#D7DCE2"/><Setter Property="Margin" Value="6"/><Setter Property="Padding" Value="8"/></Style><Style x:Key="GridText" TargetType="TextBlock"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Background" Value="#050A0D"/><Setter Property="Padding" Value="4,1,4,1"/></Style><Style x:Key="GridEdit" TargetType="TextBox"><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="Background" Value="#050A0D"/><Setter Property="BorderBrush" Value="#0078D7"/></Style><Style TargetType="DataGridColumnHeader"><Setter Property="Background" Value="#D7DCE2"/><Setter Property="Foreground" Value="#111111"/><Setter Property="FontWeight" Value="SemiBold"/></Style><Style TargetType="DataGrid"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="RowBackground" Value="#050A0D"/><Setter Property="AlternatingRowBackground" Value="#050A0D"/><Setter Property="GridLinesVisibility" Value="All"/><Setter Property="HorizontalGridLinesBrush" Value="#607D8B"/><Setter Property="VerticalGridLinesBrush" Value="#607D8B"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="HeadersVisibility" Value="Column"/><Setter Property="RowHeaderWidth" Value="0"/></Style><Style TargetType="DataGridRow"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/></Style><Style TargetType="TabControl"><Setter Property="Background" Value="#050A0D"/></Style><Style TargetType="TabItem"><Setter Property="Foreground" Value="#111111"/><Setter Property="Padding" Value="8,3"/></Style></Window.Resources><Grid Margin="12" Background="#050A0D"><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/><RowDefinition Height="180"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><Grid Grid.Row="0"><Grid.ColumnDefinitions><ColumnDefinition Width="1*" MinWidth="440"/><ColumnDefinition Width="1.65*" MinWidth="560"/></Grid.ColumnDefinitions><GroupBox Header="Prerequisites" Grid.Column="0"><Grid><Grid.RowDefinitions><RowDefinition Height="42"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><UniformGrid Columns="4"><StackPanel Orientation="Horizontal"><TextBlock Text="PowerShell:"/><TextBlock x:Name="lblPS"/></StackPanel><StackPanel Orientation="Horizontal"><TextBlock Text="VCF PowerCLI:"/><TextBlock x:Name="lblPCLI"/></StackPanel><StackPanel Orientation="Horizontal"><TextBlock Text="ImportExcel:"/><TextBlock x:Name="lblExcel"/></StackPanel><StackPanel Orientation="Horizontal"><TextBlock Text="Posh-SSH:"/><TextBlock x:Name="lblSsh"/></StackPanel></UniformGrid><StackPanel Grid.Row="1" Orientation="Horizontal"><Button x:Name="btnRecheck" Content="Recheck"/><Button x:Name="btnInstallPowerCLI" Content="Install VCF PowerCLI"/><Button x:Name="btnInstallExcel" Content="Install ImportExcel"/><Button x:Name="btnInstallSSH" Content="Install Posh-SSH"/></StackPanel></Grid></GroupBox><GroupBox Header="Desired ESX Configuration" Grid.Column="1"><Grid Margin="6"><Grid.ColumnDefinitions><ColumnDefinition Width="110"/><ColumnDefinition Width="2*"/><ColumnDefinition Width="24"/><ColumnDefinition Width="110"/><ColumnDefinition Width="1.15*"/></Grid.ColumnDefinitions><Grid.RowDefinitions><RowDefinition Height="32"/><RowDefinition Height="32"/><RowDefinition Height="30"/></Grid.RowDefinitions><TextBlock Text="DNS servers" VerticalAlignment="Center"/><TextBox x:Name="txtDns" Grid.Column="1" VerticalAlignment="Center"/><TextBlock Grid.Column="3" Text="Search domains" Margin="12,4,8,4" VerticalAlignment="Center"/><TextBox x:Name="txtDomains" Grid.Column="4" VerticalAlignment="Center"/><TextBlock Grid.Row="1" Text="NTP servers" VerticalAlignment="Center"/><TextBox x:Name="txtNtp" Grid.Row="1" Grid.Column="1" VerticalAlignment="Center"/><StackPanel Grid.Row="2" Grid.Column="1" Grid.ColumnSpan="4" Orientation="Horizontal" Margin="0,4,0,0"><CheckBox x:Name="chkApply" Content="Apply remediation" Foreground="#E6E6E6" IsChecked="True" Margin="0,0,36,0"/><CheckBox x:Name="chkClean" Content="Clean vSAN residue" Foreground="#E6E6E6"/></StackPanel></Grid></GroupBox></Grid><TabControl Grid.Row="1" Margin="0,8,0,0"><TabItem Header="Validation"><Grid Margin="8" Background="#050A0D"><Grid.RowDefinitions><RowDefinition Height="*"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><DataGrid x:Name="gridValidation" AutoGenerateColumns="False" CanUserAddRows="False"><DataGrid.Columns><DataGridTextColumn Header="Host FQDN" Binding="{Binding TargetHost}" Width="2*" ElementStyle="{StaticResource GridText}" EditingElementStyle="{StaticResource GridEdit}"/><DataGridTextColumn Header="User Name" Binding="{Binding Username}" Width="*" ElementStyle="{StaticResource GridText}" EditingElementStyle="{StaticResource GridEdit}"/><DataGridTemplateColumn Header="Password" Width="*"><DataGridTemplateColumn.CellTemplate><DataTemplate><TextBlock Text="********" Style="{StaticResource GridText}"/></DataTemplate></DataGridTemplateColumn.CellTemplate><DataGridTemplateColumn.CellEditingTemplate><DataTemplate><PasswordBox/></DataTemplate></DataGridTemplateColumn.CellEditingTemplate></DataGridTemplateColumn></DataGrid.Columns></DataGrid><StackPanel Grid.Row="1" Orientation="Horizontal" Margin="0,4,0,0"><Button x:Name="btnRun" Content="Run Readiness"/><TextBlock Text="Parallel nodes:" VerticalAlignment="Center"/><ComboBox x:Name="cmbParallel" Width="54" SelectedIndex="1"><ComboBoxItem>3</ComboBoxItem><ComboBoxItem>4</ComboBoxItem><ComboBoxItem>5</ComboBoxItem></ComboBox><Button x:Name="btnAdd" Content="Add Host"/><Button x:Name="btnRemove" Content="Remove Selected"/><Button x:Name="btnLoad" Content="Load CSV"/><Button x:Name="btnSave" Content="Save CSV"/><Button x:Name="btnExample" Content="Download Example CSV"/></StackPanel></Grid></TabItem><TabItem Header="Results"><DataGrid x:Name="gridResults" AutoGenerateColumns="True" IsReadOnly="True"/></TabItem><TabItem Header="JSON Generator"><Grid Margin="8" Background="#050A0D"><GroupBox Header="Bulk Commission JSON Settings"><Grid><Grid.ColumnDefinitions><ColumnDefinition Width="160"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions><Grid.RowDefinitions><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="34"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><TextBlock Text="SDDC Manager FQDN"/><TextBox x:Name="txtSddc" Grid.Column="1"/><TextBlock Grid.Row="1" Text="User"/><TextBox x:Name="txtSddcUser" Grid.Row="1" Grid.Column="1" Text="administrator@vsphere.local"/><TextBlock Grid.Row="2" Text="Password"/><PasswordBox x:Name="txtSddcPass" Grid.Row="2" Grid.Column="1"/><TextBlock Grid.Row="3" Text="Network Pool Name"/><ComboBox x:Name="cmbPool" Grid.Row="3" Grid.Column="1" IsEditable="True"/><TextBlock Grid.Row="4" Text="Storage Type"/><ComboBox x:Name="cmbStorage" Grid.Row="4" Grid.Column="1" SelectedIndex="0"><ComboBoxItem>vSAN OSA</ComboBoxItem><ComboBoxItem>vSAN Remote</ComboBoxItem><ComboBoxItem>vSAN ESA</ComboBoxItem><ComboBoxItem>vSAN Max</ComboBoxItem><ComboBoxItem>NFS</ComboBoxItem><ComboBoxItem>VMFS on FC</ComboBoxItem><ComboBoxItem>vVol</ComboBoxItem></ComboBox><StackPanel Grid.Row="5" Grid.ColumnSpan="2" Orientation="Horizontal" HorizontalAlignment="Center"><Button x:Name="btnConnect" Content="Connect" Width="120"/><Button x:Name="btnJson" Content="Generate JSON" Width="130"/></StackPanel></Grid></GroupBox></Grid></TabItem></TabControl><GroupBox Grid.Row="2" Header="Log"><TextBox x:Name="txtLog" IsReadOnly="True" TextWrapping="Wrap" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto" FontFamily="Consolas" FontSize="12" Background="#050A0D" Foreground="#E6E6E6"/></GroupBox><StackPanel Grid.Row="3" Orientation="Horizontal" HorizontalAlignment="Center"><Button x:Name="btnOpen" Content="Open Report"/><Button x:Name="btnClose" Content="Close"/><Button x:Name="btnStop" Content="Stop" IsEnabled="False"/></StackPanel></Grid></Window>
'@
$w=[Windows.Markup.XamlReader]::Parse($xaml)
foreach($n in 'lblPS','lblPCLI','lblExcel','lblSsh','btnRecheck','btnInstallPowerCLI','btnInstallExcel','btnInstallSSH','txtDns','txtDomains','txtNtp','cmbParallel','chkApply','chkClean','gridValidation','gridResults','btnAdd','btnRemove','btnLoad','btnSave','btnExample','txtLog','btnRun','btnStop','btnOpen','btnClose','txtSddc','txtSddcUser','txtSddcPass','btnConnect','cmbPool','cmbStorage','btnJson'){Set-Variable -Scope Script -Name $n -Value $w.FindName($n)}
$script:Targets=New-Object System.Collections.ObjectModel.ObservableCollection[object];$script:Rows=New-Object System.Collections.ObjectModel.ObservableCollection[object];$gridValidation.ItemsSource=$script:Targets;$gridResults.ItemsSource=$script:Rows;1..2|ForEach-Object{$script:Targets.Add([pscustomobject]@{TargetHost='';Username='root';Password=''})|Out-Null}
$gridValidation.AddHandler([System.Windows.Controls.PasswordBox]::PasswordChangedEvent,[System.Windows.RoutedEventHandler]{param($s,$e);$p=$e.OriginalSource;if($p-is[System.Windows.Controls.PasswordBox]-and$p.DataContext){$p.DataContext.Password=$p.Password}})
$btnRecheck.Add_Click({Prereq})
$installAll={try{EnsurePrerequisites}catch{[System.Windows.MessageBox]::Show($_.Exception.Message,'Prerequisite install failed')|Out-Null}}
$btnInstallPowerCLI.Add_Click($installAll)
$btnInstallExcel.Add_Click($installAll)
$btnInstallSSH.Add_Click($installAll)
$btnOpen.Add_Click({if($script:LastReportPath -and (Test-Path $script:LastReportPath)){Invoke-Item $script:LastReportPath}else{[System.Windows.MessageBox]::Show('No report has been generated yet.','No report')|Out-Null}})
$btnClose.Add_Click({$w.Close()})
$btnStop.Add_Click({$script:StopRequested=$true;$btnStop.IsEnabled=$false;Log 'Stop requested by operator.' WARN})
$btnAdd.Add_Click({$script:Targets.Add([pscustomobject]@{TargetHost='';Username='root';Password=''})|Out-Null})
$btnRemove.Add_Click({foreach($i in @($gridValidation.SelectedItems)){$script:Targets.Remove($i)|Out-Null}})
$btnLoad.Add_Click({$dlg=New-Object Microsoft.Win32.OpenFileDialog;$dlg.Filter='CSV files (*.csv)|*.csv|All files (*.*)|*.*';if($dlg.ShowDialog()){$script:Targets.Clear();$rows=@(Import-Csv $dlg.FileName);if($rows.Count){$txtDns.Text=$rows[0].DnsServers;$txtDomains.Text=$rows[0].SearchDomains;$txtNtp.Text=$rows[0].NtpServers};$rows|ForEach-Object{$script:Targets.Add([pscustomobject]@{TargetHost=$_.TargetHost;Username=if($_.Username){$_.Username}else{'root'};Password=$_.Password})|Out-Null};Log "Loaded $($rows.Count) rows and saved configuration."}})
$btnSave.Add_Click({$p=Join-Path $script:RunDir 'validation-targets.csv';@(TargetRows)|ForEach-Object{[pscustomobject]@{TargetHost=$_.TargetHost;Username=$_.Username;Password=$_.Password;DnsServers=$txtDns.Text;SearchDomains=$txtDomains.Text;NtpServers=$txtNtp.Text}}|Export-Csv -NoTypeInformation $p;Log "Saved validation CSV: $p";[System.Windows.MessageBox]::Show("WARNING: ESXi passwords were saved in clear text.`n`nProtect this CSV with restrictive NTFS permissions and delete it when no longer needed.`n`n$p",'Plaintext password saved','OK','Warning')|Out-Null})
$btnExample.Add_Click({$p=Join-Path $script:RunDir 'example-validation-targets.csv';@([pscustomobject]@{TargetHost='pod01esx12.corp.example.com';Username='root';Password='example'})|Export-Csv -NoTypeInformation -Path $p;Log "Example CSV saved: $p"})
$btnConnect.Add_Click({try{ConnectPools}catch{Log $_.Exception.Message ERROR;[System.Windows.MessageBox]::Show($_.Exception.Message,'Network Pool connect failed')|Out-Null}})
$btnJson.Add_Click({try{GenJson;[System.Windows.MessageBox]::Show('JSON generated and opened.','JSON generated')|Out-Null}catch{Log $_.Exception.Message ERROR;[System.Windows.MessageBox]::Show($_.Exception.Message,'Generate JSON failed')|Out-Null}})
$btnRun.Add_Click({try{if($script:IsRunning){return};ValidateInputs;if($chkClean.IsChecked){$ans=[System.Windows.MessageBox]::Show('Clean vSAN residue is destructive. It removes vSAN membership and resets non-boot disks to GPT. Boot disks are skipped. Continue?','Destructive vSAN Cleanup','YesNo','Warning');if($ans -ne 'Yes'){return}};$script:IsRunning=$true;$script:StopRequested=$false;$btnRun.IsEnabled=$false;$btnStop.IsEnabled=$true;$script:Rows.Clear();$sum=@();$det=@();$targets=TargetRows;Log "Validation rows committed. Filtered target count=$($targets.Count). Hosts=$(@($targets|ForEach-Object{$_.TargetHost})-join ',')";$throttle=[int]([System.Windows.Controls.ComboBoxItem]$cmbParallel.SelectedItem).Content;foreach($r in @(InvokeParallelHosts $targets $throttle)){$sum+=$r.Summary;$det+=$r.Details;$script:Rows.Add($r.Summary)|Out-Null;$gridResults.Items.Refresh();DoEvents};$rep=ExportReport $sum $det;Log "Readiness complete. Report=$rep"}catch{Log $_.Exception.Message ERROR;[System.Windows.MessageBox]::Show($_.Exception.Message,'Run Readiness failed')|Out-Null}finally{$script:IsRunning=$false;$btnStop.IsEnabled=$false;$btnRun.IsEnabled=$true;Prereq}})
Prereq
Log "Script started. Output: $script:RunDir"
$w.ShowDialog()|Out-Null